sys_variable_value.value:
(function (outputs, steps, params, stepResult, assertEqual) {

	var bLog = false;
	var _gtSREST = new global.GlobalToolsScriptedREST();
	var _gtATF = new global.GlobalToolsATF('GlobalToolsScriptedREST', _gtSREST, bLog, outputs, steps, params, stepResult, assertEqual);

	var fnRequest = function (oQueryParams, oBodyData, sUri) {
		return { queryParams: (oQueryParams || {}), pathParams: {}, body: { data: (oBodyData || {}) }, uri: (sUri || '/api/now/globaltools/atf') };

	}; // function fnRequest mocks a scripted REST request
	var fnResponse = function () {
		return { _status: '', _body: null, _error: null, _contentType: '', setContentType: function (s) { this['_contentType'] = s; }, setStatus: function (i) { this['_status'] = i; }, setBody: function (o) { this['_body'] = o; }, setError: function (e) { this['_error'] = e; } };
	}; // function fnResponse mocks a scripted REST response and records calls

	// getData (read) is exercised in JSON mode so no real response is required
	_gtATF.runATF('getData', /"incident":\[/, fnRequest({ max_return_items: ['1'] }), fnResponse(), { sAction: 'read', oTables: { incident: {} } }, true); // basic keyed result
	_gtATF.runATF('getData', /"iNumberOfRecordsReturned":/, fnRequest({ max_return_items: ['1'] }), fnResponse(), { sAction: 'read', oTables: { incident: {} }, bReturnNumberOfRecords: true }, true); // record count requested
	_gtATF.runATF('getData', /"Incident":\[/, fnRequest({ max_return_items: ['1'] }), fnResponse(), { sAction: 'read', oTables: { incident: {} }, bUseTableLabel: true }, true); // table label key
	_gtATF.runATF('getData', /"sysUser":\[/, fnRequest({ max_return_items: ['1'] }), fnResponse(), { sAction: 'read', oTables: { sys_user: {} }, bUseTableCamelCaseLabel: true }, true); // camel case table label key
	_gtATF.runATF('getData', {}, fnRequest(), fnResponse(), { sAction: 'insert', oTables: { incident: {} } }, true); // non read action rejected (405_002)
	_gtATF.runATF('getData', {}, fnRequest(), fnResponse(), 'notanobject', true); // missing config object (405_001)
	_gtATF.runATF('getData', {}, fnRequest({ max_return_items: ['1'] }), fnResponse(), { sAction: 'read', oTables: { incident: {} }, aMandatoryQueryParams: 'company' }, true); // mandatory query param missing (400_001)
	_gtATF.runATF('getData', {}, fnRequest({ encoded_query: ['zzz_not_a_field_xyz=1'] }), fnResponse(), { sAction: 'read', oTables: { incident: {} }, sCheckEncodedQueryParam: 'encoded_query' }, true); // invalid encoded query (400_007)
	_gtATF.runATF('getData', /"incident":\[/, fnRequest({ max_return_items: ['1'] }), fnResponse(), { sAction: 'read', oTables: { incident: {} }, bLogToTable: true, sLogTable: 'syslog' }, true); // logRequest path via getData logging
	
	// setData (write) returns nothing, so assert against the mock response it populates
	var oRespBadAction = fnResponse();
	_gtSREST.setData(fnRequest(null, { incident: {} }), oRespBadAction, { sAction: 'badaction', oTables: { incident: {} } });
	if (!oRespBadAction['_error']) { _gtATF.addError('setData', 'invalid action did not set a response error.'); } // if no error
	var oRespNoBody = fnResponse();
	_gtSREST.setData(fnRequest(null, {}), oRespNoBody, { sAction: 'insert', oTables: { incident: {} } });
	if (!oRespNoBody['_error']) { _gtATF.addError('setData', 'empty body did not set a response error.'); } // if no error
	var oRespNoTable = fnResponse();
	_gtSREST.setData(fnRequest(null, { problem: {} }), oRespNoTable, { sAction: 'insert', oTables: { incident: {} } });
	if (!oRespNoTable['_error']) { _gtATF.addError('setData', 'missing body table did not set a response error.'); } // if no error
	var oRespNoConfig = fnResponse();
	_gtSREST.setData(fnRequest(null, { incident: {} }), oRespNoConfig, 'notanobject');
	if (!oRespNoConfig['_error']) { _gtATF.addError('setData', 'missing config did not set a response error.'); } // if no error
	var oRespInsert = fnResponse();
	var sMarker = 'GlobalToolsScriptedREST ATF ' + new GlideDateTime().getNumericValue(); // unique short description
	_gtSREST.setData(fnRequest(null, { incident: { short_description: sMarker } }), oRespInsert, { sAction: 'insert', oTables: { incident: {} }, bNoWorkflow: true });
	var sNewIncidentId = (oRespInsert['_body']) ? String(oRespInsert['_body']['sys_id']) : ''; // created record id
	if (oRespInsert['_status'] != 201) { _gtATF.addError('setData', 'insert did not return status 201, got: ' + oRespInsert['_status']); } // if not 201
	if ((!sNewIncidentId) || (sNewIncidentId.length != 32)) { _gtATF.addError('setData', 'insert did not return a valid sys_id, got: ' + sNewIncidentId); } // if no sys_id
	var grNewIncident = new GlideRecord('incident'); // clean up the created test record
	if ((sNewIncidentId) && (grNewIncident.get(sNewIncidentId))) { grNewIncident.deleteRecord(); } // if cleanup

	return _gtATF.endATF();
	
})(outputs, steps, params, stepResult, assertEqual);
